  1→/**
  2→ * BrowserTab — native Electron BrowserView for one browser tab.
  3→ *
  4→ * Architecture: Renders a placeholder <div> and measures its bounds via
  5→ * ResizeObserver. Tells the main process to create/position a native BrowserView there.
  6→ * Unlike iframes, native BrowserViews bypass X-Frame-Options so any URL loads.
  7→ *
  8→ * All tabs stack via CSS Grid ([grid-area:1/1]) in the parent container.
  9→ * The native BrowserView floats above the DOM; overlays only show when view is hidden.
 10→ *
 11→ * Communication channels (each concern gets its own reliable path):
 12→ *   - IPC events: page-load, title-changed, url-change (push from Electron webContents)
 13→ *   - executeJavaScript: console drain + inspect event drain (pull from React)
 14→ *
 15→ * SPA navigation: pushState/replaceState patches in the init script fire
 16→ * browser:url-change events so the URL bar stays current.
 17→ */
 18→
 19→import {
 20→  useRef,
 21→  useState,
 22→  useEffect,
 23→  useLayoutEffect,
 24→  useCallback,
 25→  useImperativeHandle,
 26→  forwardRef,
 27→} from "react";
 28→import { match } from "ts-pattern";
 29→import { Button } from "@/components/ui/button";
 30→import { AlertCircle, Loader2, Globe } from "lucide-react";
 31→import { native } from "@/platform";
 32→import { BROWSER_PAGE_LOAD, BROWSER_TITLE_CHANGED, BROWSER_URL_CHANGE } from "@shared/events";
 33→import { getErrorMessage } from "@shared/lib/errors";
 34→import type { BrowserTabState, BrowserTabHandle, ConsoleLog, ElementSelectedEvent } from "../types";
 35→import { deriveTitleFromUrl } from "../types";
 36→import {
 37→  INSPECT_MODE_SETUP,
 38→  INSPECT_MODE_ENABLE,
 39→  INSPECT_MODE_DISABLE,
 40→  INSPECT_MODE_DRAIN_EVENTS,
 41→  INSPECT_MODE_VERIFY,
 42→} from "../automation/inspect-mode";
 43→import { VISUAL_EFFECTS_SETUP } from "../automation/visual-effects";
 44→
 45→/** How often to drain console logs from the webview (ms) */
 46→const CONSOLE_DRAIN_INTERVAL_MS = 1500;
 47→
 48→interface BrowserTabProps {
 49→  tab: BrowserTabState;
 50→  /** Update tab state in the parent — (tabId, updates) */
 51→  onUpdateTab: (tabId: string, updates: Partial<BrowserTabState>) => void;
 52→  /** Add a log line to the tab's console — (tabId, level, message) */
 53→  onAddLog: (tabId: string, level: ConsoleLog["level"], message: string) => void;
 54→  /** Whether this tab is the active (visible) tab */
 55→  visible: boolean;
 56→  /** Callback when user selects an element in inspect mode */
 57→  onElementSelected?: (tabId: string, event: ElementSelectedEvent) => void;
 58→  /** Which Electron window to create child BrowserViews in. Defaults to "main". */
 59→  windowLabel?: string;
 60→  /** When true, the browser container is constrained to mobile width (390px).
 61→   *  Used to trigger a bounds sync — mx-auto centering shifts x-offset
 62→   *  and ResizeObserver may not catch position-only changes. */
 63→  mobileView?: boolean;
 64→}
 65→
 66→export const BrowserTab = forwardRef<BrowserTabHandle, BrowserTabProps>(function BrowserTab(
 67→  { tab, onUpdateTab, onAddLog, visible, onElementSelected, windowLabel, mobileView },
 68→  ref
 69→) {
 70→  const placeholderRef = useRef<HTMLDivElement>(null);
 71→  // Ref = source of truth for imperative callbacks (always fresh)
 72→  const webviewCreatedRef = useRef(false);
 73→  // State = triggers effects when webview is ready
 74→  const [webviewReady, setWebviewReady] = useState(false);
 75→  // Track whether first page load completed (show overlay only during initial load)
 76→  const [hasLoaded, setHasLoaded] = useState(false);
 77→  // Brief "completing" state for loading bar finish animation (fill → fade)
 78→  const [completingLoad, setCompletingLoad] = useState(false);
 79→  const completingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 80→  // Guard against unmount during async webview creation
 81→  const mountedRef = useRef(true);
 82→  // Debounce bounds sync to one per animation frame
 83→  const rafRef = useRef(0);
 84→  // Track whether automation scripts (inspect mode + visual effects) have been injected
 85→  const automationInjectedRef = useRef(false);
 86→  // Ref to latest tab state — used in event handlers to read current history
 87→  const tabRef = useRef(tab);
 88→  tabRef.current = tab;
 89→  // Guard: suppress history push during back/forward navigation
 90→  // (did-navigate fires for loadURL too, which would double-push)
 91→  const suppressHistoryPushRef = useRef(false);
 92→  // Stable ref for onElementSelected callback (used by the inspect drain loop)
 93→  const onElementSelectedRef = useRef(onElementSelected);
 94→  onElementSelectedRef.current = onElementSelected;
 95→  // Track previous mobileView value to detect actual toggles (vs initial mount)
 96→  const prevMobileViewRef = useRef(mobileView);
 97→
 98→  const tabId = tab.id;
 99→  const webviewLabel = tab.webviewLabel;
100→
101→  // --- Unmount guard ---
102→  useEffect(() => {
103→    mountedRef.current = true;
104→    return () => {
105→      mountedRef.current = false;
106→      cancelAnimationFrame(rafRef.current);
107→      if (completingTimerRef.current) clearTimeout(completingTimerRef.current);
108→    };
109→  }, []);
110→
111→  // --- Create webview (lazy, on first navigation) ---
112→
113→  const createWebviewIfNeeded = useCallback(
114→    async (url: string) => {
115→      if (webviewCreatedRef.current) return;
116→
117→      // Set flag SYNCHRONOUSLY before await to prevent the auto-navigate
118→      // effect from re-firing during the async gap (onUpdateTab triggers
119→      // re-render → effect re-runs → ref still false → duplicate create).
120→      webviewCreatedRef.current = true;
121→
122→      const el = placeholderRef.current;
123→      if (!el) {
124→        webviewCreatedRef.current = false;
125→        return;
126→      }
127→
128→      const rect = el.getBoundingClientRect();
129→      try {
130→        await native.browserViews.create({
131→          label: webviewLabel,
132→          url,
133→          x: rect.x,
134→          y: rect.y,
135→          width: Math.max(rect.width, 100),
136→          height: Math.max(rect.height, 100),
137→          windowLabel: windowLabel ?? "main",
138→        });
139→
140→        // Guard: component may have unmounted during await
141→        if (!mountedRef.current) {
142→          native.browserViews.close(webviewLabel).catch(() => {});
143→          return;
144→        }
145→
146→        setWebviewReady(true);
147→
148→        // Start hidden — will show after first page load completes
149→        native.browserViews.hide(webviewLabel).catch(() => {});
150→
151→        onAddLog(tabId, "info", `Native webview created: ${webviewLabel}`);
152→      } catch (err) {
153→        // Reset flag so "Try Again" can re-attempt creation
154→        webviewCreatedRef.current = false;
155→        if (!mountedRef.current) return;
156→        onUpdateTab(tabId, { error: `Failed to create webview: ${err}`, loading: false });
157→        onAddLog(tabId, "error", `Webview creation failed: ${err}`);
158→      }
159→    },
160→    [webviewLabel, tabId, onUpdateTab, onAddLog, windowLabel]
161→  );
162→
163→  // --- Cleanup on unmount ---
164→  useEffect(() => {
165→    const label = webviewLabel;
166→    return () => {
167→      if (webviewCreatedRef.current) {
168→        native.browserViews.close(label).catch(() => {});
169→        webviewCreatedRef.current = false;
170→      }
171→    };
172→  }, [webviewLabel]);
173→
174→  // --- Auto-navigate hydrated tabs (restored from workspace persistence) ---
175→  // When a tab mounts with a persisted URL but no webview, auto-create it.
176→  // This handles workspace-switch where old webviews are destroyed and new
177→  // BrowserTab components mount with pre-filled URLs from the layout store.
178→  useEffect(() => {
179→    if (!visible || webviewCreatedRef.current || !tab.currentUrl) return;
180→    // Schedule async to avoid cascading renders from setState in effect
181→    const timer = setTimeout(() => {
182→      onUpdateTab(tabId, { loading: true });
183→      createWebviewIfNeeded(tab.currentUrl);
184→    }, 0);
185→    return () => clearTimeout(timer);
186→  }, [visible, tab.currentUrl, tabId, createWebviewIfNeeded, onUpdateTab]);
187→
188→  // --- Show/hide webview based on visibility + load state ---
189→  // Native webviews render ABOVE the DOM, so we hide them to reveal overlays.
190→  // Show only when: visible, loaded, and no initial error.
191→  useEffect(() => {
192→    if (!webviewReady) return;
193→
194→    if (visible && hasLoaded) {
195→      // Sync bounds before showing (layout may have changed while hidden)
196→      const el = placeholderRef.current;
197→      if (el) {
198→        const rect = el.getBoundingClientRect();
199→        native.browserViews
200→          .setBounds(webviewLabel, {
201→            x: rect.x,
202→            y: rect.y,
203→            width: rect.width,
204→            height: rect.height,
205→          })
206→          .then(() => native.browserViews.show(webviewLabel))
207→          .catch(() => {});
208→      } else {
209→        native.browserViews.show(webviewLabel).catch(() => {});
210→      }
211→    } else {
212→      native.browserViews.hide(webviewLabel).catch(() => {});
213→    }
214→  }, [visible, webviewReady, hasLoaded, webviewLabel]);
215→
216→  // --- Sync bounds with ResizeObserver (only when visible & loaded) ---
217→  useEffect(() => {
218→    if (!visible || !webviewReady || !hasLoaded) return;
219→
220→    const el = placeholderRef.current;
221→    if (!el) return;
222→
223→    const syncBounds = () => {
224→      cancelAnimationFrame(rafRef.current);
225→      rafRef.current = requestAnimationFrame(() => {
226→        const rect = el.getBoundingClientRect();
227→        if (rect.width === 0 || rect.height === 0) return;
228→        native.browserViews
229→          .setBounds(webviewLabel, {
230→            x: rect.x,
231→            y: rect.y,
232→            width: rect.width,
233→            height: rect.height,
234→          })
235→          .catch(() => {});
236→      });
237→    };
238→
239→    const observer = new ResizeObserver(syncBounds);
240→    observer.observe(el);
241→
242→    // Also sync on window resize (catches position-only changes)
243→    window.addEventListener("resize", syncBounds);
244→
245→    return () => {
246→      observer.disconnect();
247→      window.removeEventListener("resize", syncBounds);
248→      cancelAnimationFrame(rafRef.current);
249→    };
250→  }, [visible, webviewReady, hasLoaded, webviewLabel]);
251→
252→  // --- Re-sync bounds when mobile view toggles ---
253→  // The container CSS changes (w-full ↔ w-[390px] + mx-auto centering) change
254→  // BOTH the placeholder's size and its x-offset. ResizeObserver catches the
255→  // size change asynchronously, but it fires between layout and paint — racing
256→  // with effect-based sync can produce stale x-offsets.
257→  //
258→  // useLayoutEffect runs synchronously after React commits DOM but BEFORE the
259→  // browser paints. Calling getBoundingClientRect() here forces a synchronous
260→  // reflow that includes the newly committed CSS classes (w-[390px], mx-auto).
261→  // This guarantees correct width AND x-position in a single measurement — no
262→  // rAF, no race with ResizeObserver, no timing ambiguity.
263→  //
264→  // The hide → setBounds → show cycle ensures WKWebView's native compositor
265→  // actually repositions the view (setBounds on an already-visible native view
266→  // can be coalesced/ignored by the compositor in some environments).
267→  useLayoutEffect(() => {
268→    const changed = prevMobileViewRef.current !== mobileView;
269→    prevMobileViewRef.current = mobileView;
270→    if (!changed) return; // skip initial mount — visibility effect handles it
271→
272→    if (!visible || !webviewReady || !hasLoaded) return;
273→    const el = placeholderRef.current;
274→    if (!el || !webviewCreatedRef.current) return;
275→
276→    // Hide so the stale-position webview isn't visible during the transition.
277→    native.browserViews.hide(webviewLabel).catch(() => {});
278→
279→    // getBoundingClientRect() forces synchronous reflow — reads the post-toggle
280→    // layout including mx-auto centering offsets. No rAF needed because React
281→    // has already committed the DOM changes before useLayoutEffect runs.
282→    const rect = el.getBoundingClientRect();
283→    if (rect.width === 0 || rect.height === 0) return;
284→
285→    native.browserViews
286→      .setBounds(webviewLabel, {
287→        x: rect.x,
288→        y: rect.y,
289→        width: rect.width,
290→        height: rect.height,
291→      })
292→      .then(() => native.browserViews.show(webviewLabel))
293→      .catch(() => {});
294→  }, [mobileView, visible, webviewReady, hasLoaded, webviewLabel]);
295→
296→  // --- IPC event listeners (page load, title, SPA nav) ---
297→  useEffect(() => {
298→    const unlistenFns: Array<() => void> = [];
299→
300→    // Page load events
301→    unlistenFns.push(
302→      native.events.on(BROWSER_PAGE_LOAD, (data) => {
303→        const { label, url, event: eventType } = data;
304→        if (label !== webviewLabel) return;
305→
306→        if (eventType === "started") {
307→          // Clear any pending completion animation
308→          if (completingTimerRef.current) clearTimeout(completingTimerRef.current);
309→          setCompletingLoad(false);
310→          // Reset injection flag — new page context destroys window.__deusVisuals
311→          automationInjectedRef.current = false;
312→          // Don't reset hasLoaded — once the first page has loaded, keep the
313→          // BrowserView visible. Subsequent navigations (redirects, SPA nav,
314→          // meta refresh) show the top loading bar, not the full-screen spinner.
315→          onUpdateTab(tabId, { loading: true });
316→        } else if (eventType === "finished") {
317→          setHasLoaded(true);
318→          // Trigger completion animation (bar fills to 100% → fades)
319→          setCompletingLoad(true);
320→          completingTimerRef.current = setTimeout(() => setCompletingLoad(false), 500);
321→          onUpdateTab(tabId, { loading: false, currentUrl: url, error: null });
322→          onAddLog(tabId, "info", `Page loaded: ${url}`);
323→        }
324→      })
325→    );
326→
327→    // Title change events (regular, non-deus title changes)
328→    unlistenFns.push(
329→      native.events.on(BROWSER_TITLE_CHANGED, (data) => {
330→        const { label, title } = data;
331→        if (label !== webviewLabel) return;
332→        onUpdateTab(tabId, { title });
333→      })
334→    );
335→
336→    // Navigation events (did-navigate, did-navigate-in-page, pushState/replaceState)
337→    // Push to history so back/forward buttons work for all navigations.
338→    unlistenFns.push(
339→      native.events.on(BROWSER_URL_CHANGE, (data) => {
340→        const { label, url } = data;
341→        if (label !== webviewLabel) return;
342→
343→        // Suppress history push from programmatic back/forward navigation
344→        if (suppressHistoryPushRef.current) {
345→          suppressHistoryPushRef.current = false;
346→          onUpdateTab(tabId, { url, currentUrl: url, title: deriveTitleFromUrl(url) });
347→          return;
348→        }
349→
350→        const current = tabRef.current;
351→        // Skip duplicate URLs (e.g. hash-only changes that resolve to same URL)
352→        if (current.currentUrl === url) {
353→          onUpdateTab(tabId, { title: deriveTitleFromUrl(url) });
354→          return;
355→        }
356→        // Truncate forward history and append the new URL
357→        const newHistory = current.history.slice(0, current.historyIndex + 1);
358→        newHistory.push(url);
359→        onUpdateTab(tabId, {
360→          url,
361→          currentUrl: url,
362→          title: deriveTitleFromUrl(url),
363→          history: newHistory,
364→          historyIndex: newHistory.length - 1,
365→        });
366→      })
367→    );
368→
369→    // Console logs are drained via eval_browser_webview_with_result in the
370→    // "Periodic console drain" effect below.
371→    //
372→    // Inspect mode events are delivered SOLELY via buffer + drain polling
373→    // (eval_browser_webview_with_result every 200ms). We intentionally do NOT
374→    // use the title-channel for inspect events — it has two independent writers
375→    // (BROWSER_INIT_SCRIPT's SPA nav + inspect script) racing on document.title,
376→    // causing silent message loss via WKWebView's title-change coalescing.
377→
378→    return () => unlistenFns.forEach((fn) => fn());
379→  }, [webviewLabel, tabId, onUpdateTab, onAddLog]);
380→
381→  // --- Periodic console drain (only when visible and webview ready) ---
382→  // Uses eval_browser_webview_with_result (native completion handler) instead
383→  // of the old title-channel approach (drain_browser_console). The title-channel
384→  // suffers from WKWebView's title-change coalescing — when the 60ms restore
385→  // window overlaps with another title write (SPA nav, page itself), the
386→  // \x01CL: message is silently dropped and console logs are lost.
387→  //
388→  // The completion-handler path reads the log buffer directly and returns the
389→  // JSON via WKWebView's evaluateJavaScript callback, which is reliable.
390→  useEffect(() => {
391→    if (!visible || !webviewReady || !hasLoaded) return;
392→
393→    const CONSOLE_DRAIN_JS = `(function(){
394→      var b = window.__DEUS_LOGS__ || [];
395→      window.__DEUS_LOGS__ = [];
396→      return JSON.stringify(b);
397→    })()`;
398→
399→    // Track consecutive failures for diagnostic logging
400→    let consoleDrainFails = 0;
401→    // Guard against overlapping async drains — if invoke() takes longer than
402→    // the interval, skip until the previous call completes.
403→    let inFlight = false;
404→
405→    const interval = setInterval(async () => {
406→      if (inFlight) return;
407→      inFlight = true;
408→      try {
409→        const result = await native.browserViews.evaluateWithResult(
410→          webviewLabel,
411→          CONSOLE_DRAIN_JS,
412→          2000
413→        );
414→        // Reset on success
415→        consoleDrainFails = 0;
416→
417→        if (!result || result === "[]" || result === "undefined") return;
418→
419→        let logs: Array<{ l: string; m: string; t: number }>;
420→        try {
421→          logs = JSON.parse(result);
422→        } catch (parseErr) {
423→          console.error(
424→            "[BrowserTab] console drain: JSON.parse failed",
425→            parseErr,
426→            "raw:",
427→            result.slice(0, 200)
428→          );
429→          return;
430→        }
431→        for (const log of logs) {
432→          const level = match(log.l)
433→            .with("warn", () => "warn" as const)
434→            .with("error", () => "error" as const)
435→            .with("debug", () => "debug" as const)
436→            .otherwise(() => "info" as const);
437→          onAddLog(tabId, level, log.m);
438→        }
439→      } catch (err) {
440→        consoleDrainFails++;
441→        if (consoleDrainFails <= 3 || consoleDrainFails % 50 === 0) {
442→          console.warn(
443→            `[BrowserTab] console drain failed (${consoleDrainFails}x):`,
444→            getErrorMessage(err)
445→          );
446→        }
447→      } finally {
448→        inFlight = false;
449→      }
450→    }, CONSOLE_DRAIN_INTERVAL_MS);
451→
452→    return () => clearInterval(interval);
453→  }, [visible, webviewReady, hasLoaded, webviewLabel, tabId, onAddLog]);
454→
455→  // --- Periodic inspect event drain (only when selector is active) ---
456→  // Drains buffered events from the inject script via
457→  // eval_browser_webview_with_result (native completion handler).
458→  // This is the sole delivery path for inspect events — we do not use
459→  // the title-channel for inspect events (see file-level comment).
460→  useEffect(() => {
461→    if (!visible || !webviewReady || !hasLoaded || !tab.selectorActive) return;
462→    // Poll at 200ms — fast enough for responsive feel after click,
463→    // cheap because eval_browser_webview_with_result returns immediately
464→    // when the buffer is empty ("[]").
465→    const INSPECT_DRAIN_MS = 200;
466→
467→    // Track consecutive failures to avoid log spam (log first 3, then every 50th)
468→    let failCount = 0;
469→    // Guard against overlapping async drains — if invoke() takes longer than
470→    // the interval, skip until the previous call completes.
471→    let inFlight = false;
472→
473→    const interval = setInterval(async () => {
474→      if (inFlight) return;
475→      inFlight = true;
476→      try {
477→        const result = await native.browserViews.evaluateWithResult(
478→          webviewLabel,
479→          INSPECT_MODE_DRAIN_EVENTS,
480→          2000
481→        );
482→        // Reset fail counter on success
483→        failCount = 0;
484→
485→        if (!result || result === "[]" || result === "undefined") return;
486→
487→        let events: Array<{ type: string; data: Record<string, unknown> }>;
488→        try {
489→          events = JSON.parse(result);
490→        } catch (parseErr) {
491→          // JSON parse failure — log the raw result for debugging
492→          console.error(
493→            "[BrowserTab] inspect drain: JSON.parse failed",
494→            parseErr,
495→            "raw result:",
496→            result.slice(0, 200)
497→          );
498→          return;
499→        }
500→
501→        for (const evt of events) {
502→          match(evt.type)
503→            .with("element-event", () => {
504→              const parsed = evt.data as unknown as ElementSelectedEvent;
505→              onElementSelectedRef.current?.(tabId, parsed);
506→              onAddLog(
507→                tabId,
508→                "info",
509→                parsed.type === "area-selected"
510→                  ? `Area selected: ${parsed.bounds?.width}\u00d7${parsed.bounds?.height}`
511→                  : `Element selected: ${parsed.element?.tagName}${parsed.reactComponent ? ` (${parsed.reactComponent.name})` : ""}`
512→              );
513→            })
514→            .with("selection-mode", () => {
515→              const modeData = evt.data as { active: boolean };
516→              onUpdateTab(tabId, { selectorActive: modeData.active });
517→            })
518→            .otherwise(() => {});
519→        }
520→      } catch (err) {
521→        failCount++;
522→        if (failCount <= 3 || failCount % 50 === 0) {
523→          console.warn(`[BrowserTab] inspect drain failed (${failCount}x):`, getErrorMessage(err));
524→        }
525→      } finally {
526→        inFlight = false;
527→      }
528→    }, INSPECT_DRAIN_MS);
529→
530→    return () => clearInterval(interval);
531→  }, [
532→    visible,
533→    webviewReady,
534→    hasLoaded,
535→    tab.selectorActive,
536→    webviewLabel,
537→    tabId,
538→    onUpdateTab,
539→    onAddLog,
540→  ]);
541→
542→  // --- Imperative methods exposed to parent ---
543→
544→  const navigateToUrl = useCallback(
545→    async (url: string) => {
546→      if (!webviewCreatedRef.current) {
547→        // First navigation — create webview with this URL
548→        await createWebviewIfNeeded(url);
549→      } else {
550→        // Webview exists — navigate it
551→        try {
552→          await native.browserViews.navigate(webviewLabel, url);
553→        } catch (err) {
554→          onAddLog(tabId, "error", `Navigation failed: ${err}`);
555→        }
556→      }
557→    },
558→    [webviewLabel, tabId, createWebviewIfNeeded, onAddLog]
559→  );
560→
561→  /** Navigate using native goBack/goForward — preserves scroll/form state */
562→  const goBack = useCallback(() => {
563→    if (!webviewCreatedRef.current) return;
564→    suppressHistoryPushRef.current = true;
565→    native.browserViews.goBack(webviewLabel).catch((err) => {
566→      suppressHistoryPushRef.current = false;
567→      onAddLog(tabId, "error", `Go back failed: ${err}`);
568→    });
569→  }, [webviewLabel, tabId, onAddLog]);
570→
571→  const goForward = useCallback(() => {
572→    if (!webviewCreatedRef.current) return;
573→    suppressHistoryPushRef.current = true;
574→    native.browserViews.goForward(webviewLabel).catch((err) => {
575→      suppressHistoryPushRef.current = false;
576→      onAddLog(tabId, "error", `Go forward failed: ${err}`);
577→    });
578→  }, [webviewLabel, tabId, onAddLog]);
579→
580→  const reload = useCallback(() => {
581→    if (!webviewCreatedRef.current) return;
582→    native.browserViews.reload(webviewLabel).catch((err) => {
583→      onAddLog(tabId, "error", `Reload failed: ${err}`);
584→    });
585→  }, [webviewLabel, tabId, onAddLog]);
586→
587→  // Inject visual effects and inspect mode into the BrowserView.
588→  // Uses fire-and-forget eval for dispatch + eval_with_result for verification
589→  // (fire-and-forget can't detect JS runtime errors in the IIFE).
590→  const injectAutomation = useCallback(async () => {
591→    if (!webviewCreatedRef.current) return;
592→    if (automationInjectedRef.current) {
593→      onAddLog(tabId, "info", "Automation already injected");
594→      return;
595→    }
596→
597→    try {
598→      // Inject visual effects and inspect mode via native eval
599→      await native.browserViews.evaluate(webviewLabel, INSPECT_MODE_SETUP);
600→      await native.browserViews.evaluate(webviewLabel, VISUAL_EFFECTS_SETUP);
601→
602→      // Wait a tick for the IIFEs to execute, then verify inspect mode
603→      await new Promise((r) => setTimeout(r, 100));
604→      try {
605→        const verifyResult = await native.browserViews.evaluateWithResult(
606→          webviewLabel,
607→          INSPECT_MODE_VERIFY,
608→          3000
609→        );
610→        if (!verifyResult) return;
611→        const status = JSON.parse(verifyResult);
612→        if (!status.deusInspect || !status.hasDrainEvents) {
613→          onAddLog(tabId, "error", `Inspect mode setup incomplete: ${JSON.stringify(status)}`);
614→          return; // Don't mark as injected
615→        }
616→      } catch (verifyErr) {
617→        onAddLog(tabId, "warn", `Inspect verification failed: ${getErrorMessage(verifyErr)}`);
618→        return;
619→      }
620→
621→      automationInjectedRef.current = true;
622→      onUpdateTab(tabId, { injected: true, injectionFailed: false });
623→      onAddLog(tabId, "info", "Automation scripts injected successfully");
624→    } catch (err) {
625→      onAddLog(tabId, "error", `Injection failed: ${getErrorMessage(err)}`);
626→      onUpdateTab(tabId, { injectionFailed: true });
627→    }
628→  }, [tabId, webviewLabel, onUpdateTab, onAddLog]);
629→
630→  // Auto-inject on first page load — single call to injectAutomation().
631→  useEffect(() => {
632→    if (!hasLoaded || automationInjectedRef.current) return;
633→    injectAutomation();
634→  }, [hasLoaded, injectAutomation]);
635→
636→  const toggleElementSelector = useCallback(async () => {
637→    if (!webviewCreatedRef.current) return;
638→
639→    // Auto-inject if not yet injected
640→    if (!automationInjectedRef.current) {
641→      await injectAutomation();
642→    }
643→
644→    const enabling = !tab.selectorActive;
645→    const js = enabling ? INSPECT_MODE_ENABLE : INSPECT_MODE_DISABLE;
646→
647→    // Use eval_browser_webview_with_result for the toggle so we can detect
648→    // JS errors. The ENABLE/DISABLE IIFEs don't return a value (undefined),
649→    // but any thrown error will be reported via the completion handler.
650→    try {
651→      await native.browserViews.evaluateWithResult(webviewLabel, js, 3000);
652→      onAddLog(tabId, "info", enabling ? "Inspect mode activated" : "Inspect mode deactivated");
653→      onUpdateTab(tabId, { selectorActive: enabling });
654→    } catch (err) {
655→      onAddLog(tabId, "error", `Inspect mode toggle failed: ${getErrorMessage(err)}`);
656→    }
657→  }, [webviewLabel, tabId, tab.selectorActive, injectAutomation, onUpdateTab, onAddLog]);
658→
659→  const syncBounds = useCallback(() => {
660→    const el = placeholderRef.current;
661→    if (!el || !webviewCreatedRef.current) return;
662→    const rect = el.getBoundingClientRect();
663→    if (rect.width === 0 || rect.height === 0) return;
664→    native.browserViews
665→      .setBounds(webviewLabel, {
666→        x: rect.x,
667→        y: rect.y,
668→        width: rect.width,
669→        height: rect.height,
670→      })
671→      .catch(() => {});
672→  }, [webviewLabel]);
673→
674→  useImperativeHandle(
675→    ref,
676→    () => ({
677→      navigateToUrl,
678→      goBack,
679→      goForward,
680→      reload,
681→      injectAutomation,
682→      toggleElementSelector,
683→      syncBounds,
684→    }),
685→    [navigateToUrl, goBack, goForward, reload, injectAutomation, toggleElementSelector, syncBounds]
686→  );
687→
688→  return (
689→    // Placeholder div — native webview is positioned to overlay this area.
690→    //
691→    // All tabs stack in the same grid cell via [grid-area:1/1] (parent is
692→    // display:grid). This replaced the old `absolute inset-0` wrapper because
693→    // absolute positioning didn't reliably inherit width constraints from the
694→    // containing block when parent containers toggled mobile view (w-full ↔
695→    // w-[390px] + mx-auto). getBoundingClientRect() returned stale full-width
696→    // values, so the native WKWebView never repositioned. Grid stacking keeps
697→    // tabs in normal document flow — they inherit the container's width
698→    // naturally and ResizeObserver fires on actual size changes.
699→    <div ref={placeholderRef} className="relative [grid-area:1/1]">
700→      {/* Loading progress bar — NProgress-style, top of viewport.
701→       * Shows during page loads (indeterminate animation → fills to 92%).
702→       * On load complete: fills to 100% then fades out.
703→       * Uses transform: scaleX() for GPU-accelerated animation. */}
704→      {visible && (tab.loading || completingLoad) && (
705→        <div
706→          className="bg-primary absolute inset-x-0 top-0 z-10 h-[2px] origin-left"
707→          style={{
708→            animation: tab.loading
709→              ? "browser-loading 8s cubic-bezier(.19,1,.22,1) forwards"
710→              : "browser-loading-complete 0.4s ease-out forwards",
711→          }}
712→        />
713→      )}
714→
715→      {/* Empty state: no URL entered yet — minimal, engineer-friendly */}
716→      {visible && !webviewReady && !tab.currentUrl && (
717→        <div className="flex h-full flex-col items-center justify-center gap-3">
718→          <div className="bg-muted/50 flex h-10 w-10 items-center justify-center rounded-xl">
719→            <Globe
720→              className="text-muted-foreground/60 h-5 w-5"
721→              strokeWidth={1.5}
722→              aria-hidden="true"
723→            />
724→          </div>
725→          <div className="text-center">
726→            <p className="text-muted-foreground text-sm">
727→              Paste a URL above or ask the Agent to browse
728→            </p>
729→            <p className="text-muted-foreground/40 mt-1 text-xs">
730→              Supports any website — cookies, auth, and devtools included
731→            </p>
732→          </div>
733→        </div>
734→      )}
735→
736→      {/* Loading overlay: only during initial page load (webview hidden) */}
737→      {visible && tab.loading && !hasLoaded && (
738→        <div className="vibrancy-bg absolute inset-0 flex items-center justify-center">
739→          <Loader2 className="text-primary h-8 w-8 animate-spin" />
740→        </div>
741→      )}
742→
743→      {/* Error overlay: only if initial load failed */}
744→      {visible && tab.error && !hasLoaded && (
745→        <div className="vibrancy-bg absolute inset-0 flex items-center justify-center">
746→          <div className="max-w-sm p-8 text-center">
747→            <div className="bg-destructive/10 mx-auto mb-4 flex h-10 w-10 items-center justify-center rounded-xl">
748→              <AlertCircle className="text-destructive h-5 w-5" />
749→            </div>
750→            <h3 className="mb-1 text-sm font-semibold">Unable to Load Page</h3>
751→            <p className="text-muted-foreground mb-4 text-xs">{tab.error}</p>
752→            <Button
753→              size="sm"
754→              variant="outline"
755→              onClick={() => {
756→                onUpdateTab(tabId, { error: null });
757→                if (tab.currentUrl) navigateToUrl(tab.currentUrl);
758→              }}
759→            >
760→              Try Again
761→            </Button>
762→          </div>
763→        </div>
764→      )}
765→    </div>
766→  );
767→});
